import{createDesmosGraphs,getDesmosSlider}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({voxels:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.61,-.72,-.33,.63,-.7,.34,-.48,0,.88]},bounds:{xmin:-1.25,xmax:1.25,ymin:-1.25,ymax:1.25,zmin:-1.25,zmax:1.25},expressions:[{latex:raw`f(x, y, z) = \frac{1}{1.5} x + y + z`,hidden:!0},...getDesmosSlider({expression:"n = 8",min:4,max:16,step:1,secret:!1}),{latex:raw`X = [(i, j) \for i = [-1 + \frac{1}{n}, -1 + \frac{3}{n}, ..., 1 - \frac{1}{n}], j = [-1 + \frac{1}{n}, -1 + \frac{3}{n}, ..., 1 - \frac{1}{n}]]`,hidden:!0,secret:!0},{latex:raw`N(x) = \frac{2}{n}(\round(\frac{n}{2}x + \frac{\mod(n, 2)}{2}) - \frac{\mod(n, 2)}{2})`,hidden:!0,secret:!0},{latex:raw`N_f(x) = \frac{2}{n}(\round(\frac{n}{2}x + \frac{1 - \mod(n, 2)}{2}) - \frac{1 - \mod(n, 2)}{2})`,hidden:!0,secret:!0},{latex:raw`\left|z\right| \leq N(\sqrt{1 - X.x^2 - X.y^2}) \{X.x - \frac{1}{n} \leq x \leq X.x + \frac{1}{n}\} \{X.y - \frac{1}{n} \leq y \leq X.y + \frac{1}{n}\} \{ \left|X\right| < 1 \}`,colorLatex:"C",secret:!0},{latex:raw`f_R(x, y, z) = f(N_f(x), N_f(y), N_f(z))`,hidden:!0,secret:!0},{latex:raw`P(x, y, z) = e^{-f_R(x, y, z)^2}`,secret:!0},{latex:raw`R(x, y, z) = \{ f_R(x, y, z) \geq 0 : 1 - P(x, y, z), f_R(x, y, z) < 0: 0 \}`,secret:!0},{latex:raw`B(x, y, z) = \{ f_R(x, y, z) \leq 0 : 1 - P(x, y, z), f_R(x, y, z) > 0: 0 \}`,secret:!0},{latex:raw`C = \operatorname{rgb}(204R(x, y, z) + 40B(x, y, z) + 122P(x, y, z), 40R(x, y, z) + 122B(x, y, z) + 40P(x, y, z), 40R(x, y, z) + 204B(x, y, z) + 205P(x, y, z))`,secret:!0}]}})}